var line = msg.payload.trim();

// Ignore startup messages or empty lines
if (!line.includes("MOTION:")) {
    return null;
}

var parsed = {};
var pairs = line.split(",");

for (var i = 0; i < pairs.length; i++) {
    var parts = pairs[i].split(":");
    if (parts.length === 2) {
        var key = parts[0].trim();
        var value = parts[1].trim();

        // Convert numbers, leave strings as strings
        if (key === "RFID") {
            parsed[key] = value;
        } else {
            parsed[key] = parseFloat(value);
        }
    }
}

msg.payload = parsed;
flow.set("sensorData", msg.payload);
return msg;

var data = msg.payload;

msg.payload = {
    temperature: data.TEMP,
    humidity: data.HUMIDITY,
    light: data.LIGHT,
    loudness: data.LOUDNESS,
    motion: data.MOTION,
    rfid: data.RFID
};

msg.headers = {
    "Content-Type": "application/json"
};

return msg;

var data = msg.payload;
var now = Date.now();

// Track how long PIR has detected no motion
var pirNoMotionSeconds = flow.get("pirNoMotionSeconds") || 0;

if (data.MOTION === 0) {
    pirNoMotionSeconds += 2;
} else {
    pirNoMotionSeconds = 0;
}
flow.set("pirNoMotionSeconds", pirNoMotionSeconds);

// Decide whether to trigger CNN
var CNN_TRIGGER_SECONDS = 15;  // short for testing, increase for real use
var lastCNNTriggerTime = flow.get("lastCNNTriggerTime") || 0;
var triggerCNN = false;

// Only trigger if PIR has been still long enough
// AND enough time has passed since last trigger
if (pirNoMotionSeconds >= CNN_TRIGGER_SECONDS) {
    if (now - lastCNNTriggerTime >= CNN_TRIGGER_SECONDS * 1000) {
        triggerCNN = true;
        flow.set("lastCNNTriggerTime", now);
    }
}

msg.payload = {
    loudness: data.LOUDNESS,
    triggerCNN: triggerCNN
};

msg.topic = "infant/camera/input";

return msg;

var data = msg.payload;
var rfid = data.RFID;
var now = Date.now();

var lastCareTime = flow.get("lastCareTime") || null;
var lastNurseID = flow.get("lastNurseID") || "NONE";

if (rfid !== "NONE") {
    lastCareTime = now;
    lastNurseID = rfid;
    flow.set("lastCareTime", lastCareTime);
    flow.set("lastNurseID", lastNurseID);

    // Nurse is attending, so crying escalation restarts from LOW
    // We don't clear the alert directly - Alert Escalation handles that
    flow.set("cryingStartTime", null);
    flow.set("cryingGraceStart", null);
}

var minutesSinceCare;
var careOverdue;

if (lastCareTime === null) {
    minutesSinceCare = -1;
    careOverdue = true;
} else {
    minutesSinceCare = Math.floor((now - lastCareTime) / 60000);
    careOverdue = minutesSinceCare >= 180;
}

flow.set("minutesSinceCare", minutesSinceCare);

msg.payload = {
    lastCareTime: lastCareTime ? new Date(lastCareTime).toISOString() : "never",
    lastNurseID: lastNurseID,
    minutesSinceCare: minutesSinceCare,
    careOverdue: careOverdue,
    rfidJustTapped: (rfid !== "NONE"),
    timestamp: new Date().toISOString()
};

msg.topic = "infant/care";

return msg;

var data = msg.payload;

msg.payload = {
    temperature: data.TEMP,
    humidity: data.HUMIDITY
};

msg.topic = "infant/env";

return msg;

// Triggered by either camera data (on change) or sensor data (every 2 seconds)
// When triggered by sensor data, re-evaluates using the last known camera state
var camera;
if (msg.topic === "infant/camera") {
    camera = msg.payload;
    flow.set("cameraData", camera);
} else {
    camera = flow.get("cameraData") || null;
    if (!camera) {
        return null;  // No camera data yet, nothing to evaluate
    }
}

var previousState = flow.get("infantState") || "UNKNOWN";
var now = Date.now();
var lastFaceSeenTime = flow.get("lastFaceSeenTime") || 0;

// How long to keep previous state when HOG loses the face
// Prevents false ABSENT from baby turning head briefly
var GRACE_PERIOD_MS = 15000;  // 15 seconds 

var state = "UNKNOWN";

// HOG currently sees a face - this is the most reliable signal
var hogSeesFace = (camera.state === "sleeping" || camera.state === "awake");
var isCrying = (camera.crying === true);

if (hogSeesFace || isCrying) {
    // We can see a face, so we know exactly what's happening
    flow.set("lastFaceSeenTime", now);

    if (isCrying) {
        state = "CRYING";
    } else if (camera.state === "awake") {
        state = "AWAKE";
    } else {
        state = "SLEEPING";
    }
}
else {
    // HOG cannot see a face right now
    var timeSinceLastFace = now - lastFaceSeenTime;

    if (lastFaceSeenTime === 0) {
        // System just started, HOG has never seen a face
        if (camera.presence === "not_found") {
            state = "ABSENT";
        } else {
            state = "UNKNOWN";
        }
    }
    else if (timeSinceLastFace < GRACE_PERIOD_MS) {
        // Within grace period - baby probably just turned their head
        if (previousState !== "UNKNOWN" && previousState !== "ABSENT") {
            state = previousState;
        } else {
            state = "UNKNOWN";
        }
    }
    else {
        // Grace period expired - now trust CNN result
        if (camera.presence === "not_found") {
            state = "ABSENT";
        } else {
            // CNN sees someone but HOG can't find a face
            // Baby might be face-down or turned away
            if (camera.cameraMotion === true) {
                state = "AWAKE";
            } else if (camera.cameraMotion === false) {
                state = "SLEEPING";
            } else {
                if (previousState !== "UNKNOWN" && previousState !== "ABSENT") {
                    state = previousState;
                } else {
                    state = "SLEEPING";
                }
            }
        }
    }
}

flow.set("infantState", state);

var pirNoMotionSeconds = flow.get("pirNoMotionSeconds") || 0;

msg.payload = {
    state: state,
    previousState: previousState,
    stateChanged: (state !== previousState),
    presence: camera.presence,
    faceState: camera.state,
    crying: camera.crying,
    cameraMotion: camera.cameraMotion,
    pirNoMotionSeconds: pirNoMotionSeconds,
    timestamp: new Date().toISOString()
};

msg.topic = "infant/state";

return msg;

var state = flow.get("infantState") || "UNKNOWN";
var minutesSinceCare = flow.get("minutesSinceCare") || 0;
var camera = flow.get("cameraData") || {};
var sensors = flow.get("sensorData") || {};
var previousAlert = flow.get("alertLevel") || "NONE";
var now = Date.now();

// Thresholds (short for testing, increase for real use)
var CRYING_ESCALATE_MINUTES = 5;
var CARE_OVERDUE_MINUTES = 10;
var MOTION_ALERT_DURATION_MS = 60000;  // Show motion alert for 60 seconds
var CRYING_GRACE_MS = 10000;           // 10 second grace before resetting crying timer

// --- Crying duration tracking with grace period ---
// If crying stops briefly (less than 10 seconds), don't reset the timer
// This handles fidgety crying babies who pause momentarily
var cryingStartTime = flow.get("cryingStartTime") || null;
var cryingGraceStart = flow.get("cryingGraceStart") || null;
var cryingDurationMins = 0;

if (state === "CRYING") {
    // Baby is crying right now
    cryingGraceStart = null;
    flow.set("cryingGraceStart", null);

    if (cryingStartTime === null) {
        // Just started crying
        flow.set("cryingStartTime", now);
        cryingDurationMins = 0;
    } else {
        cryingDurationMins = Math.floor((now - cryingStartTime) / 60000);
    }
} else {
    // Baby is not crying right now
    if (cryingStartTime !== null) {
        // Was crying before, start grace period
        if (cryingGraceStart === null) {
            flow.set("cryingGraceStart", now);
        } else if (now - cryingGraceStart >= CRYING_GRACE_MS) {
            // Grace period expired, baby genuinely stopped crying
            flow.set("cryingStartTime", null);
            flow.set("cryingGraceStart", null);
            cryingStartTime = null;
        }
        // During grace period, keep the crying duration for reference
        if (cryingStartTime !== null) {
            cryingDurationMins = Math.floor((now - cryingStartTime) / 60000);
        }
    }
}

// --- Motion alert tracking ---
// When a triggered motion check returns false, store the time
// Keep the alert visible for MOTION_ALERT_DURATION_MS so nurses can see it
var motionAlertTime = flow.get("motionAlertTime") || null;
var previousCameraMotion = flow.get("previousCameraMotion");

if (camera.cameraMotion === false && previousCameraMotion !== false) {
    // Fresh negative motion result just came in
    flow.set("motionAlertTime", now);
    motionAlertTime = now;
}
flow.set("previousCameraMotion", camera.cameraMotion);

var motionAlertActive = (motionAlertTime !== null && (now - motionAlertTime) < MOTION_ALERT_DURATION_MS);

// --- Determine alert level ---
var alertLevel = "NONE";
var alertReason = "";
var buzzerCommand = "BUZZER:OFF";
var ledCommand = "LED:NONE";

// Priority 1: Baby not in crib
if (state === "ABSENT") {
    alertLevel = "HIGH";
    alertReason = "Baby not detected in crib";
    buzzerCommand = "BUZZER:ON";
    ledCommand = "LED:HIGH";
}

// Priority 2: Baby crying
if (alertLevel === "NONE" && state === "CRYING") {
    if (cryingDurationMins >= CRYING_ESCALATE_MINUTES) {
        alertLevel = "HIGH";
        alertReason = "Baby has been crying for " + cryingDurationMins + " minutes";
        buzzerCommand = "BUZZER:ON";
        ledCommand = "LED:HIGH";
    } else if (minutesSinceCare !== -1 && minutesSinceCare >= CRYING_ESCALATE_MINUTES) {
        alertLevel = "HIGH";
        alertReason = "Baby crying, no nurse check-in for " + minutesSinceCare + " minutes";
        buzzerCommand = "BUZZER:ON";
        ledCommand = "LED:HIGH";
    } else {
        alertLevel = "LOW";
        alertReason = "Baby is crying (" + cryingDurationMins + " mins)";
        ledCommand = "LED:LOW";
    }
}

// Priority 3: Motion check was negative (stays visible for 60 seconds)
if (alertLevel === "NONE" && motionAlertActive && camera.presence === "infant_present") {
    alertLevel = "LOW";
    alertReason = "Baby has not moved during motion check";
    ledCommand = "LED:LOW";
}

// Priority 4: Care overdue
if (alertLevel === "NONE") {
    if (minutesSinceCare === -1) {
        alertLevel = "LOW";
        alertReason = "No nurse has checked in since system started";
        ledCommand = "LED:LOW";
    } else if (minutesSinceCare >= CARE_OVERDUE_MINUTES) {
        alertLevel = "LOW";
        alertReason = "Routine check-in overdue (" + minutesSinceCare + " minutes)";
        ledCommand = "LED:LOW";
    }
}

// --- Possible causes when crying ---
var possibleCauses = [];
if (state === "CRYING") {
    if (sensors && sensors.TEMP !== undefined) {
        if (sensors.TEMP > 26) {
            possibleCauses.push("Possibly too warm (" + sensors.TEMP.toFixed(1) + "C)");
        }
        if (sensors.TEMP < 18) {
            possibleCauses.push("Possibly too cold (" + sensors.TEMP.toFixed(1) + "C)");
        }
    }

    if (minutesSinceCare === -1 || minutesSinceCare >= 120) {
        possibleCauses.push("Possibly hungry (no recent care event logged)");
    }

    var recentLoudness = flow.get("recentLoudness") || [];
    var currentLoudness = (sensors && sensors.LOUDNESS) ? sensors.LOUDNESS : 0;
    recentLoudness.push(currentLoudness);
    if (recentLoudness.length > 30) recentLoudness.shift();
    flow.set("recentLoudness", recentLoudness);

    if (recentLoudness.length >= 15) {
        var olderAvg = 0;
        for (var i = 0; i < 10; i++) olderAvg += recentLoudness[i];
        olderAvg = olderAvg / 10;
        var newerMax = 0;
        for (var j = recentLoudness.length - 5; j < recentLoudness.length; j++) {
            if (recentLoudness[j] > newerMax) newerMax = recentLoudness[j];
        }
        if (newerMax > olderAvg * 2) {
            possibleCauses.push("Possibly startled by sudden noise");
        }
    }
}

flow.set("alertLevel", alertLevel);

// --- Build outputs ---
var alertChanged = (alertLevel !== previousAlert);

// Output 1: alert data to MQTT (only when something changed)
var alertMsg = null;
if (alertLevel !== "NONE" || previousAlert !== "NONE") {
    alertMsg = {
        payload: {
            alertLevel: alertLevel,
            alertReason: alertReason,
            possibleCauses: possibleCauses,
            alertChanged: alertChanged,
            infantState: state,
            cryingDurationMins: cryingDurationMins,
            minutesSinceCare: minutesSinceCare,
            cameraMotion: camera.cameraMotion,
            timestamp: new Date().toISOString()
        },
        topic: "infant/alerts"
    };
}

// Output 2: actuator commands (only when alert level changes)
// Prevents flooding Arduino with repeated BUZZER:OFF every 2 seconds
var actuatorMsg = null;
if (alertChanged) {
    actuatorMsg = {payload: buzzerCommand + "\n" + ledCommand + "\n"};
}

return [alertMsg, actuatorMsg];

var state = flow.get("infantState") || "UNKNOWN";
var alertLevel = flow.get("alertLevel") || "NONE";
var minutesSinceCare = flow.get("minutesSinceCare") || 0;
var lastNurseID = flow.get("lastNurseID") || "NONE";
var pirNoMotionSeconds = flow.get("pirNoMotionSeconds") || 0;
var sensors = flow.get("sensorData") || {};
var camera = flow.get("cameraData") || {};

msg.payload = {
    infantState: state,
    alertLevel: alertLevel,
    minutesSinceCare: minutesSinceCare,
    lastNurseID: lastNurseID,
    pirNoMotionSeconds: pirNoMotionSeconds,
    temperature: sensors.TEMP,
    humidity: sensors.HUMIDITY,
    light: sensors.LIGHT,
    loudness: sensors.LOUDNESS,
    motion: sensors.MOTION,
    cameraPresence: camera.presence,
    cameraFaceState: camera.state,
    cameraCrying: camera.crying,
    cameraMotion: camera.cameraMotion,
    timestamp: new Date().toISOString()
};

msg.headers = {
    "Content-Type": "application/json"
};

return msg;
